SELECT EXISTS (
    SELECT 1
    FROM c_owner_property
    WHERE tenant_id = #{tenantId}
      AND building_id = #{buildingId}
      AND room_id = #{roomId}
      AND uid = #{ownerUid}
      AND account_status = 1
)

mapper.update:
UPDATE t_repair_acceptance_policy_snapshot
SET status = 'SUPERSEDED'
WHERE work_order_id = #{workOrderId}
  AND tenant_id = #{tenantId}
  AND status = 'ACTIVE'

mapper.insert:
INSERT INTO t_repair_acceptance_affected_owner (
    policy_id, tenant_id, room_id, owner_uid, affected_reason
) VALUES (
    #{policyId}, #{tenantId}, #{roomId}, #{ownerUid}, #{affectedReason}
)

mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM t_repair_acceptance_affected_owner
    WHERE policy_id = #{policyId}
      AND tenant_id = #{tenantId}
      AND room_id = #{roomId}
      AND owner_uid = #{ownerUid}
)

SELECT affected.room_id
FROM t_repair_acceptance_affected_owner affected
JOIN t_repair_acceptance_policy_snapshot policy ON policy.policy_id = affected.policy_id
WHERE policy.work_order_id = #{workOrderId}
  AND policy.tenant_id = #{tenantId}
  AND policy.status = 'ACTIVE'
  AND affected.owner_uid = #{ownerUid}
ORDER BY affected.room_id

INSERT INTO t_repair_acceptance (
    work_order_id, tenant_id, policy_id, round_no, submitted_by_user_id
)
SELECT #{workOrderId}, #{tenantId}, #{policyId},
       COALESCE(MAX(round_no), 0) + 1, #{submittedByUserId}
FROM t_repair_acceptance
WHERE work_order_id = #{workOrderId}
RETURNING acceptance_id

SELECT acceptance_id, work_order_id, tenant_id, policy_id, round_no, status
FROM t_repair_acceptance
WHERE acceptance_id = #{acceptanceId}
  AND tenant_id = #{tenantId}

mapper.update:
UPDATE t_repair_acceptance
SET status = #{status},
    completed_by_user_id = #{completedByUserId},
    completed_at = CURRENT_TIMESTAMP,
    completion_remark = #{completionRemark}
WHERE acceptance_id = #{acceptanceId}
  AND tenant_id = #{tenantId}
  AND status = 'COLLECTING'
